concept.syntax:
struct Point {
    x: f64,
    y: f64,
}

impl Point {
    // Associated function (constructor)
    fn new(x: f64, y: f64) -> Point {
        Point { x, y }    // shorthand if field name == variable
    }

    // Method — immutable access
    fn distance_from_origin(&self) -> f64 {
        (self.x * self.x + self.y * self.y).sqrt()
    }

    // Method — mutable access
    fn translate(&mut self, dx: f64, dy: f64) {
        self.x += dx;
        self.y += dy;
    }
}

demo.code:
struct Rectangle {
    width: f64,
    height: f64,
}

impl Rectangle {
    fn new(w: f64, h: f64) -> Rectangle {
        Rectangle { width: w, height: h }
    }
    fn area(&self) -> f64 {
        self.width * self.height
    }
}

fn main() {
    let r = Rectangle::new(4.0, 3.0);
    println!("Area = {}", r.area());
}

