practice.solutionCode:
struct Circle {
    radius: f64,
}

impl Circle {
    fn circumference(&self) -> f64 {
        2.0 * 3.14159 * self.radius
    }
}

fn main() {
    let c = Circle { radius: 5.0 };
    println!("{:.4}", c.circumference());
}
